route_guard.code_example:
function RequireAuth({ children, allowedRoles }: { children: ReactNode; allowedRoles?: UserRole[] }) {
  const { user, isAuthenticated } = useAuthStore();
  const location = useLocation();

  if (!isAuthenticated) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  if (allowedRoles && user && !allowedRoles.includes(user.role)) {
    return <Navigate to="/unauthorized" replace />;
  }

  return <>{children}</>;
}

permission_hook.code_example:
function usePermission(required: string | string[]): boolean {
  const { user } = useAuthStore();
  if (!user) return false;
  if (user.role === 'ADMIN') return true;
  const perms = Array.isArray(required) ? required : [required];
  return perms.every(p => user.permissions.includes(p));
}

client_implementation.code_example:
import axios from 'axios';
import { useAuthStore } from '@/stores/authStore';

const apiClient = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || 'http://localhost:8080/api',
  timeout: 15000,
  headers: { 'Content-Type': 'application/json' },
});

// Request interceptor: JWT 자동 주입
apiClient.interceptors.request.use((config) => {
  const token = useAuthStore.getState().accessToken;
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Response interceptor: 401 시 자동 refresh
apiClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    const original = error.config;
    if (error.response?.status === 401 && !original._retry) {
      original._retry = true;
      try {
        await useAuthStore.getState().refreshToken();
        original.headers.Authorization = `Bearer ${useAuthStore.getState().accessToken}`;
        return apiClient(original);
      } catch {
        useAuthStore.getState().logout();
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);

export { apiClient };

