domain_service_example.code_example:
import { apiClient } from './client';
import type { Customer, PurchaseHistory, ConsultationLog } from './types';

export const customerApi = {
  getByPhone: (phone: string) =>
    apiClient.get<Customer>(`/customers/phone/${encodeURIComponent(phone)}`).then(r => r.data),

  getPurchases: (customerId: string) =>
    apiClient.get<PurchaseHistory[]>(`/customers/${customerId}/purchases`).then(r => r.data),

  getConsultations: (customerId: string, page = 0) =>
    apiClient.get<PageResponse<ConsultationLog>>(`/customers/${customerId}/consultations`, {
      params: { page, size: 20 }
    }).then(r => r.data),
};

query_hook_example.code_example:
import { useQuery } from '@tanstack/react-query';
import { customerApi } from '@/api/customer';

export function useCustomerByPhone(phone: string) {
  return useQuery({
    queryKey: ['customer', 'phone', phone],
    queryFn: () => customerApi.getByPhone(phone),
    enabled: phone.length >= 10,  // 전화번호 최소 길이
  });
}

export function usePurchaseHistory(customerId: string | undefined) {
  return useQuery({
    queryKey: ['customer', customerId, 'purchases'],
    queryFn: () => customerApi.getPurchases(customerId!),
    enabled: !!customerId,
  });
}
